import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt3901.jpg",p=JSON.parse('{"title":"Lektion 39","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion39.md","filePath":"lektionen/lektion39.md"}'),s={name:"lektionen/lektion39.md"};function l(n,t,h,o,u,b){return e(),r("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-39" tabindex="-1">Lektion 39 <a class="header-anchor" href="#lektion-39" aria-label="Permalink to &quot;Lektion 39&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>39.1. Die Personalendungen der ersten Person (तृतीयः पुरुषः = &quot;dritte Person&quot;)</li><li>39.2. Bildung der Verbformen der ersten Person thematischer Präsensstämme <ul><li>39.2.1. Erste Präsensklasse (भ्वादि)</li><li>39.2.2. Sechste Präsensklasse (तुदादि)</li><li>39.2.3. Vierte Präsensklasse (दिवादि)</li><li>39.2.4. Zehnte Präsensklasse (चुरादि) und Kausative (णिजन्त)</li><li>39.2.5. Passiv (Suffix यक्)</li></ul></li><li>39.3. Bildung der Verbformen der ersten Person des einfachen Futur (ऌत्) <ul><li>39.3.1. अनिट्-Bildung</li><li>39.3.2. सेट्-Bildung</li></ul></li><li>39.4. Bildung der Verbformen der ersten Person athematischer Präsensstämme <ul><li>39.4.1. Zweite Präsensklasse (अदादि)</li><li>39.4.2. Dritte Präsensklasse (जुहोत्यादि)</li><li>39.4.3. Fünfte Präsensklasse (स्वादि)</li><li>39.4.4. Achte Präsensklasse (तनादि)</li><li>39.4.5. Siebte Präsensklasse (रुधादि)</li><li>39.4.6. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>39.5. Übung</li></ul><h2 id="_39-1-die-personalendungen-der-ersten-person-तृतीयः-पुरुषः-dritte-person" tabindex="-1">39.1. Die Personalendungen der ersten Person (तृतीयः पुरुषः = &quot;dritte Person&quot;) <a class="header-anchor" href="#_39-1-die-personalendungen-der-ersten-person-तृतीयः-पुरुषः-dritte-person" aria-label="Permalink to &quot;39.1. Die Personalendungen der ersten Person (तृतीयः पुरुषः = &quot;dritte Person&quot;)&quot;">​</a></h2><p>Die Endungen der ersten Person (तृतीयः पुरुषः = &quot;dritte Person&quot;) sind:</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Primärendung thematische Stämme</td><td>-mi</td><td>-mas</td></tr><tr><td>Primärendung athematische Stämme</td><td>-e</td><td></td></tr><tr><td>Sekundärendung thematische Stämme</td><td>-m</td><td>-ma</td></tr><tr><td>Sekundärendung athematische Stämme</td><td>-am</td><td></td></tr><tr><td>Optativendung</td><td>-a</td><td></td></tr><tr><td>Perfektendung</td><td>-a</td><td>-e</td></tr></tbody></table><p>1 Anmerkung: eigentlich ist die Primärendung Ā thematischer Stämme auch als -e anzusetzen, vor dem der Themavokal -a- aus Analogiegründen wegfällt. Der Effekt ist aber so, als ob die Endung -i an den Themavokal -a- treten würde: a + i » e.</p><h2 id="_39-2-bildung-der-verbformen-der-ersten-person-thematischer-prasensstamme" tabindex="-1">39.2. Bildung der Verbformen der ersten Person thematischer Präsensstämme <a class="header-anchor" href="#_39-2-bildung-der-verbformen-der-ersten-person-thematischer-prasensstamme" aria-label="Permalink to &quot;39.2. Bildung der Verbformen der ersten Person thematischer Präsensstämme&quot;">​</a></h2><p>Regel:</p><p>Vor -mi, -mas, -ma, -mahe, -mahi wird der Themavokal -a- durch -ā- ersetzt !!!</p><h3 id="_39-2-1-erste-prasensklasse-भ्वादि" tabindex="-1">39.2.1. Erste Präsensklasse (भ्वादि) <a class="header-anchor" href="#_39-2-1-erste-prasensklasse-भ्वादि" aria-label="Permalink to &quot;39.2.1. Erste Präsensklasse (भ्वादि)&quot;">​</a></h3><p>भू 1P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>भवामि</td><td>भवामस्</td></tr><tr><td>bhava + i</td><td></td><td></td></tr><tr><td>richtig: bhav-e</td><td>&lt;भवामहे&gt;</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अभवम्</td><td>अभवाम</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>भवेयम्</td><td></td></tr><tr><td>bhava + iy-am</td><td>भवेम</td><td></td></tr><tr><td>bhava +i-ma</td><td>&lt;भवेय&gt;</td><td></td></tr><tr><td>bhava + iy-a</td><td>&lt;भवेमहि&gt;</td><td></td></tr><tr><td>bhava + i-mahi</td><td></td><td></td></tr></tbody></table><h3 id="_39-2-2-sechste-prasensklasse-तुदादि" tabindex="-1">39.2.2. Sechste Präsensklasse (तुदादि) <a class="header-anchor" href="#_39-2-2-sechste-prasensklasse-तुदादि" aria-label="Permalink to &quot;39.2.2. Sechste Präsensklasse (तुदादि)&quot;">​</a></h3><p>विश् 1P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>विशामि</td><td>विशामस्</td></tr><tr><td>Imperfekt (लङ्)</td><td>अविशम्</td><td>विशाम</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>विशेयम्</td><td>विशेम</td></tr></tbody></table><h3 id="_39-2-3-vierte-prasensklasse-दिवादि" tabindex="-1">39.2.3. Vierte Präsensklasse (दिवादि) <a class="header-anchor" href="#_39-2-3-vierte-prasensklasse-दिवादि" aria-label="Permalink to &quot;39.2.3. Vierte Präsensklasse (दिवादि)&quot;">​</a></h3><p>नृत् 1P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>नृत्यामि</td><td>नृत्यामस्</td></tr><tr><td>Imperfekt (लङ्)</td><td>अनृत्यम्</td><td>अनृत्याम</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>नृत्येयम्</td><td>नृत्येम</td></tr></tbody></table><h3 id="_39-2-4-zehnte-prasensklasse-चुरादि-und-kausative-णिजन्त" tabindex="-1">39.2.4. Zehnte Präsensklasse (चुरादि) und Kausative (णिजन्त) <a class="header-anchor" href="#_39-2-4-zehnte-prasensklasse-चुरादि-und-kausative-णिजन्त" aria-label="Permalink to &quot;39.2.4. Zehnte Präsensklasse (चुरादि) und Kausative (णिजन्त)&quot;">​</a></h3><p>चुर् 10U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>चोरयामि</td><td>चोरयामस्</td></tr><tr><td>Imperfekt (लङ्)</td><td>अचोरयम्</td><td>अचोरयाम</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>चोरयेयम्</td><td>चोरयेम</td></tr></tbody></table><h3 id="_39-2-5-passiv-suffix-यक्" tabindex="-1">39.2.5. Passiv (Suffix यक्) <a class="header-anchor" href="#_39-2-5-passiv-suffix-यक्" aria-label="Permalink to &quot;39.2.5. Passiv (Suffix यक्)&quot;">​</a></h3><p>ईक्ष् 1Ā</p><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>Indikativ Präsens (लट्)</td><td>ईक्ष्ये</td><td></td></tr><tr><td>īkṣ-ya + i</td><td>ईक्ष्यामहे</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>ऐक्ष्ये</td><td></td></tr><tr><td>a + īkṣ-ya + i</td><td>ऐक्ष्यामहि</td><td></td></tr><tr><td>Optativ (विधिलिङ्)</td><td>ईक्ष्येय</td><td></td></tr><tr><td>īkṣ-ya + iy-a</td><td>ईक्ष्येमहि</td><td></td></tr><tr><td>īk-ya + i-mahi</td><td></td><td></td></tr></tbody></table><h2 id="_39-3-bildung-der-verbformen-der-ersten-person-des-einfachen-futur-ऌत्" tabindex="-1">39.3. Bildung der Verbformen der ersten Person des einfachen Futur (ऌत्) <a class="header-anchor" href="#_39-3-bildung-der-verbformen-der-ersten-person-des-einfachen-futur-ऌत्" aria-label="Permalink to &quot;39.3. Bildung der Verbformen der ersten Person des einfachen Futur (ऌत्)&quot;">​</a></h2><p>Das Futur hat thematische Bildung. Deshalb gilt auch die Regel für thematische Stämme:</p><p>Vor -mi, -mas, -mahe wird der Themavokal -a- durch -ā- ersetzt !!!</p><h3 id="_39-3-1-अनिट्-bildung" tabindex="-1">39.3.1. अनिट्-Bildung <a class="header-anchor" href="#_39-3-1-अनिट्-bildung" aria-label="Permalink to &quot;39.3.1. अनिट्-Bildung&quot;">​</a></h3><p>दा 3U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Futur (ऌत्)</td><td>दास्यामि</td><td></td></tr><tr><td>dā-syā-mi</td><td>दास्यामस्</td><td>दास्ये</td></tr></tbody></table><h3 id="_39-3-2-सेट्-bildung" tabindex="-1">39.3.2. सेट्-Bildung <a class="header-anchor" href="#_39-3-2-सेट्-bildung" aria-label="Permalink to &quot;39.3.2. सेट्-Bildung&quot;">​</a></h3><p>भू 1P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Futur (ऌत्)</td><td>भविष्यामि</td><td></td></tr><tr><td>bho + i + syā + mi</td><td>भविष्यामस्</td><td>&lt;भविष्ये&gt;</td></tr></tbody></table><h2 id="_39-4-bildung-der-verbformen-der-ersten-person-athematischer-prasensstamme" tabindex="-1">39.4. Bildung der Verbformen der ersten Person athematischer Präsensstämme <a class="header-anchor" href="#_39-4-bildung-der-verbformen-der-ersten-person-athematischer-prasensstamme" aria-label="Permalink to &quot;39.4. Bildung der Verbformen der ersten Person athematischer Präsensstämme&quot;">​</a></h2><p>Beachten Sie, dass im Wortinnern - im Gegensatz zum Satzsandhi - vor Endungen, die mit</p><ul><li>Vokal</li><li>Halbvokal</li><li>Nasal</li></ul><p>beginnen, Konsonanten in der Regel unverändert bleiben.</p><p>z. B. वच् 1.sg.Ind.Präs.P वच्मि</p><h3 id="_39-4-1-zweite-prasensklasse-अदादि" tabindex="-1">39.4.1. Zweite Präsensklasse (अदादि) <a class="header-anchor" href="#_39-4-1-zweite-prasensklasse-अदादि" aria-label="Permalink to &quot;39.4.1. Zweite Präsensklasse (अदादि)&quot;">​</a></h3><p>द्विष् 2U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>द्वेष्मि</td><td>द्विष्मस्</td></tr><tr><td>dviṣ-e</td><td>द्विष्महे</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अद्वेषम्</td><td>अद्विष्म</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>द्विष्याम्</td><td></td></tr><tr><td>dviṣ-yā + (a)m</td><td>द्विष्याम</td><td>द्विषीय</td></tr><tr><td>dviṣ-īy-a</td><td>द्विषीमहि</td><td></td></tr></tbody></table><p>अस् 2P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>अस्मि</td></tr><tr><td>s-mas</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>आसम्</td></tr><tr><td>a + as-am</td><td>आस्म</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>स्याम्</td></tr><tr><td>s-yā + (a)m</td><td>स्याम</td></tr></tbody></table><p><img src="'+i+'" alt=""><br> Abb.: सो ऽस्मि<br> [Bild: Namcha]</p><h3 id="_39-4-2-dritte-prasensklasse-जुहोत्यादि" tabindex="-1">39.4.2. Dritte Präsensklasse (जुहोत्यादि) <a class="header-anchor" href="#_39-4-2-dritte-prasensklasse-जुहोत्यादि" aria-label="Permalink to &quot;39.4.2. Dritte Präsensklasse (जुहोत्यादि)&quot;">​</a></h3><p>हु 3P</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>जुहोमि</td><td>जुहुमस्</td></tr><tr><td>ju-hu + e</td><td>&lt;जुहुमहे&gt;</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अजुहवम्</td><td></td></tr><tr><td>a-juho + am</td><td>जुहुम</td><td>&lt;अजुह्वि&gt;</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>जुहुयाम्</td><td>जुहुयाम</td></tr><tr><td>juhu + īy-a</td><td>&lt;जुह्वीमहि&gt;</td><td></td></tr></tbody></table><p>धा 3U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>दधामि</td><td>दध्मस्</td></tr><tr><td>dadh-e</td><td>दध्महे</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अदधाम्</td><td></td></tr><tr><td>a-dadh + am</td><td>दध्म</td><td>अदधि</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>दध्याम्</td><td>दध्याम</td></tr></tbody></table><h3 id="_39-4-3-funfte-prasensklasse-स्वादि" tabindex="-1">39.4.3. Fünfte Präsensklasse (स्वादि) <a class="header-anchor" href="#_39-4-3-funfte-prasensklasse-स्वादि" aria-label="Permalink to &quot;39.4.3. Fünfte Präsensklasse (स्वादि)&quot;">​</a></h3><p>Bei vokalisch auslautenden Wurzeln kann wahlweise vor mit m- beginnenden Endungen das -u des Stammbildungssuffixes (-nu) wegfallen.</p><p>सु 5U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>सुनोमि</td><td>सुनुमस्</td></tr><tr><td>सुन्मस्</td><td>सुन्वे</td><td>सुनुमहे</td></tr><tr><td>सुन्महे</td><td></td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>असुनवम्</td><td>असुनुम</td></tr><tr><td>असुन्म</td><td>असुन्वि</td><td>असुनुमहि</td></tr><tr><td>असुन्महि</td><td></td><td></td></tr><tr><td>Optativ (विधिलिङ्)</td><td>सुनुयाम्</td><td>सुनुयाम</td></tr></tbody></table><h3 id="_39-4-4-achte-prasensklasse-तनादि" tabindex="-1">39.4.4. Achte Präsensklasse (तनादि) <a class="header-anchor" href="#_39-4-4-achte-prasensklasse-तनादि" aria-label="Permalink to &quot;39.4.4. Achte Präsensklasse (तनादि)&quot;">​</a></h3><p>तन् 8U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>तनोमि</td><td>तनुमस्</td></tr><tr><td>तन्मस्</td><td>तन्वे</td><td>तनुमहे</td></tr><tr><td>तन्महे</td><td></td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अतनवम्</td><td>अतनुम</td></tr><tr><td>अतन्म</td><td>अतन्वि</td><td>अतनुमहि</td></tr><tr><td>अतन्महि</td><td></td><td></td></tr><tr><td>Optativ (विधिलिङ्)</td><td>तनुयाम्</td><td>तनुयाम</td></tr></tbody></table><p>कृ 8U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>करोमि</td><td>कुर्मस्</td></tr><tr><td>Imperfekt (लङ्)</td><td>अकरवम्</td><td>अकुर्म</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>कुर्याम्</td><td>कुर्याम</td></tr></tbody></table><h3 id="_39-4-5-siebte-prasensklasse-रुधादि" tabindex="-1">39.4.5. Siebte Präsensklasse (रुधादि) <a class="header-anchor" href="#_39-4-5-siebte-prasensklasse-रुधादि" aria-label="Permalink to &quot;39.4.5. Siebte Präsensklasse (रुधादि)&quot;">​</a></h3><p>युज् 7U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>युनज्मि</td><td></td></tr><tr><td>yu-na-j-mi</td><td>युञ्ज्मस्</td><td></td></tr><tr><td>yu + n + j-mas</td><td>युञ्जे</td><td>युञ्ज्महे</td></tr><tr><td>Imperfekt (लङ्)</td><td>अयुनजम्</td><td>अयुञ्ज्म</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>युञ्ज्याम्</td><td>युञ्ज्याम</td></tr></tbody></table><h3 id="_39-4-6-neunte-prasensklasse-क्र्यादि" tabindex="-1">39.4.6. Neunte Präsensklasse (क्र्यादि) <a class="header-anchor" href="#_39-4-6-neunte-prasensklasse-क्र्यादि" aria-label="Permalink to &quot;39.4.6. Neunte Präsensklasse (क्र्यादि)&quot;">​</a></h3><p>क्री 8U</p><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens (लट्)</td><td>क्रीणामि</td><td>क्रीणीमस्</td></tr><tr><td>krī + n-e</td><td>क्रीणीमहे</td><td></td></tr><tr><td>Imperfekt (लङ्)</td><td>अक्रीणाम्</td><td></td></tr><tr><td>a-krī + nā + am</td><td>अक्रीणीम</td><td>अक्रीणि</td></tr><tr><td>Optativ (विधिलिङ्)</td><td>क्रीणीयाम्</td><td>क्रीणीयाम</td></tr><tr><td>krī + n-īy-a</td><td>क्रीणीमहि</td><td></td></tr></tbody></table><h2 id="_39-5-ubung" tabindex="-1">39.5. Übung <a class="header-anchor" href="#_39-5-ubung" aria-label="Permalink to &quot;39.5. Übung&quot;">​</a></h2><p>Bilden Sie zu folgenden Verbformen die Formen der ersten Person, die dieser Verbform in Zahl, Zeit, Modus (Indikativ, Optativ) und Aktionsweise (P, Ā, Passiv) entsprechen.</p><p>Beispiel: गच्छन्ति » गच्छामस्</p><ol><li>अदन्ति</li><li>आसन्</li><li>असिष्यति</li><li>अर्हयन्ति</li><li>आप्नुयुः</li><li>आस्त</li><li>अश्नुते</li><li>अश्नीयात्</li><li>व्याञ्जत</li><li>ऐत्</li><li>एषिष्यन्ति</li><li>ऐक्ष्यन्त</li><li>अकुप्यत्</li><li>कुर्वीरन्</li><li>कामयन्ते</li><li>क्रुध्यति</li><li>विक्रेष्यन्ते</li><li>खाद्यते</li><li>आगच्छन्</li><li>अगीयत</li><li>चरिष्यति</li><li>अचोरयत्</li><li>चिनुयुः</li><li>छिनत्ति</li><li>अजायन्त</li><li>व्यजन्यन्त</li><li>जीवेत्</li><li>जानते</li><li>अतन्वन्</li><li>त्यज्येरन्</li><li>धक्ष्यन्ति</li><li>दत्ते</li><li>दिशेयुः</li><li>दोग्धि</li><li>दुष्यन्ति</li><li>अदृश्यत</li><li>अधत्त</li><li>द्विषीत</li><li>नीयेत</li><li>अनृत्यन्</li><li>पच्येरन्</li><li>पतन्ति</li><li>अपादयत्</li><li>पिबेत्</li><li>पिपूर्यात्</li><li>प्रक्ष्यति</li><li>बध्नन्ति</li><li>बुध्यन्ते</li><li>ब्रवीति</li><li>भजेत्</li><li>भनक्ति</li><li>बिभ्यति</li><li>भुङ्क्ते</li><li>भाव्येरन्</li><li>अबिभः</li><li>अमन्यत</li><li>अमुच्यन्त</li><li>म्रियते</li><li>इज्यन्ते</li><li>मिमीत</li><li>युञ्ज्युः</li><li>युध्यन्ते</li><li>रक्षन्ति</li><li>अरुणत्</li><li>अलभत</li><li>रोदिति</li><li>अलुभ्यन्</li><li>वक्ति</li><li>अवदत्</li><li>वत्स्यन्ति</li><li>वेत्ति</li><li>वेक्ष्यति</li><li>वस्ते</li><li>विन्देयुः</li><li>अवर्तन्त</li><li>शक्नुयात्</li><li>अशोचन्</li><li>अशृण्वन्</li><li>सीदन्ति</li><li>सिञ्चेत्</li><li>स्रक्ष्यति</li><li>सुन्वन्ति</li><li>अतिष्ठत्</li><li>स्तौति</li><li>स्मर्येत</li><li>घ्नन्ति</li><li>जहति</li><li>अजुहवुः</li><li>हरति</li></ol>',70)])])}const k=d(s,[["render",l]]);export{p as __pageData,k as default};
